#include<bits/stdc++.h>
using namespace std;
int n;
class Birthday {
	public:
	string name;
	int year, match, day,number;
};
bool cmp(Birthday a, Birthday b) {
	if (a.year == b.year) {
		if (a.match == b.match) {
			if (a.day == b.day) {
				return a.number > b.number;
			} else {
				return a.day < b.day;
			}
		} else {
			return a.match < b.match;
		}
	} else {
		return a.year < b.year;
	}
}
int main() {
	Birthday birthday[101];
	cin >> n;
	for (int i = 0; i < n; i++) {
		cin >> birthday[i].name >> birthday[i].year >> birthday[i].match >> birthday[i].day;
		birthday[i].number=i;
	}

	sort(birthday, birthday + n, cmp);
	for (int i = 0; i < n; i++) {
		cout << birthday[i].name << endl;
	}
	return 0;
}
